    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         "action": "snapshot",
        //         "arg": {
        //             "instType": "SPOT",
        //             "channel": "candle1m",
        //             "instId": "BTCUSDT"
        //         },
        //         "data": [
        //             [
        //                 "1701871620000",
        //                 "44080.23",
        //                 "44080.23",
        //                 "44028.5",
        //                 "44028.51",
        //                 "9.9287",
        //                 "437404.105512",
        //                 "437404.105512"
        //             ],
        //             [
        //                 "1701871680000",
        //                 "44028.51",
        //                 "44108.11",
        //                 "44028.5",
        //                 "44108.11",
        //                 "17.139",
        //                 "755436.870643",
        //                 "755436.870643"
        //             ],
        //         ],
        //         "ts": 1701901610417
        //     }
        //
        // uta
        //
        //     {
        //         "action": "snapshot",
        //         "arg": {
        //             "instType": "usdt-futures",
        //             "topic": "kline",
        //             "symbol": "BTCUSDT",
        //             "interval": "1m"
        //         },
        //         "data": [
        //             {
        //                 "start": "1755564480000",
        //                 "open": "116286",
        //                 "close": "116256.2",
        //                 "high": "116310.2",
        //                 "low": "116232.8",
        //                 "volume": "39.7062",
        //                 "turnover": "4616746.46654"
        //             },
        //         ],
        //         "ts": 1755594421877
        //     }
        //
        Object arg = this.safeValue(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object instType = this.safeStringLower(arg, "instType");
        Object marketType = ((Helpers.isTrue((Helpers.isEqual(instType, "spot"))))) ? "spot" : "contract";
        Object marketId = this.safeString2(arg, "instId", "symbol");
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        Object channel = this.safeString2(arg, "channel", "topic");
        Object interval = this.safeString(arg, "interval");
        Object isUta = null;
        if (Helpers.isTrue(Helpers.isEqual(interval, null)))
        {
            isUta = false;
            interval = Helpers.replace((String)channel, (String)"candle", (String)"");
        } else
        {
            isUta = true;
        }
        Object timeframes = this.safeValue(this.options, "timeframes");
        Object timeframe = this.findTimeframe(interval, timeframes);
        Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
        }
        Object data = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
        {
            Object parsed = this.parseWsOHLCV(Helpers.GetValue(data, i), market);
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        Object messageHash = null;
        if (Helpers.isTrue(isUta))
        {
            messageHash = Helpers.add("kline:", symbol);
        } else
        {
            messageHash = Helpers.add(Helpers.add(Helpers.add("candles:", timeframe), ":"), symbol);
        }
        client.resolve(stored, messageHash);
    }

    public Object parseWsOHLCV(Object ohlcv, Object... optionalArgs)
    {
        //
        //     [
        //         "1701871620000",  // timestamp
        //         "44080.23", // open
        //         "44080.23", // high
        //         "44028.5", // low
        //         "44028.51", // close
        //         "9.9287", // base volume
        //         "437404.105512", // quote volume
        //         "437404.105512" // USDT volume
        //     ]
        //
        // uta
        //
        //     {
        //         "start": "1755564480000",
        //         "open": "116286",
        //         "close": "116256.2",
        //         "high": "116310.2",
        //         "low": "116232.8",
        //         "volume": "39.7062",
        //         "turnover": "4616746.46654"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object volumeIndex = ((Helpers.isTrue((Helpers.GetValue(market, "inverse"))))) ? 6 : 5;
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(this.safeInteger2(ohlcv, "start", 0), this.safeNumber2(ohlcv, "open", 1), this.safeNumber2(ohlcv, "high", 2), this.safeNumber2(ohlcv, "low", 3), this.safeNumber2(ohlcv, "close", 4), this.safeNumber2(ohlcv, "volume", volumeIndex)));
    }

