    public void handleTrades(Client client, Object message)
    {
        //
        //     {
        //         "action": "snapshot",
        //         "arg": { "instType": "SPOT", "channel": "trade", "instId": "BTCUSDT" },
        //         "data": [
        //             {
        //                 "ts": "1701910980366",
        //                 "price": "43854.01",
        //                 "size": "0.0535",
        //                 "side": "buy",
        //                 "tradeId": "1116461060594286593"
        //             },
        //         ],
        //         "ts": 1701910980730
        //     }
        //
        // uta
        //
        //     {
        //         "action": "snapshot",
        //         "arg": { "instType": "spot", "topic": "publicTrade", "symbol": "BTCUSDT" },
        //         "data": [
        //             {
        //                 "T": "1756287827920",
        //                 "P": "110878.5",
        //                 "v": "0.07",
        //                 "S": "buy",
        //                 "L": "1344534089797185550"
        //                 "i": "1344534089797185549"
        //             },
        //         ],
        //         "ts": 1701910980730
        //     }
        //
        Object arg = this.safeValue(message, "arg", new java.util.HashMap<String, Object>() {{}});
        Object instType = this.safeStringLower(arg, "instType");
        Object marketType = ((Helpers.isTrue((Helpers.isEqual(instType, "spot"))))) ? "spot" : "contract";
        Object marketId = this.safeString2(arg, "instId", "symbol");
        Object market = this.safeMarket(marketId, null, null, marketType);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object stored = this.safeValue(this.trades, symbol);
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            stored = new ArrayCache(((Number)limit).intValue());
            Helpers.addElementToObject(this.trades, symbol, stored);
        }
        Object data = this.safeList(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object length = Helpers.getArrayLength(data);
        // fix chronological order by reversing
        for (var i = 0; Helpers.isLessThan(i, length); i++)
        {
            Object index = Helpers.subtract(Helpers.subtract(length, i), 1);
            Object rawTrade = Helpers.GetValue(data, index);
            Object parsed = this.parseWsTrade(rawTrade, market);
            Helpers.callDynamically(stored, "append", new Object[]{parsed});
        }
        Object messageHash = Helpers.add("trade:", symbol);
        client.resolve(stored, messageHash);
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        //
        //     {
        //         "ts": "1701910980366",
        //         "price": "43854.01",
        //         "size": "0.0535",
        //         "side": "buy",
        //         "tradeId": "1116461060594286593"
        //     }
        // swap private
        //
        //            {
        //               "orderId": "1169142761031114781",
        //               "tradeId": "1169142761312637004",
        //               "symbol": "LTCUSDT",
        //               "orderType": "market",
        //               "side": "buy",
        //               "price": "80.87",
        //               "baseVolume": "0.1",
        //               "quoteVolume": "8.087",
        //               "profit": "0",
        //               "tradeSide": "open",
        //               "posMode": "hedge_mode",
        //               "tradeScope": "taker",
        //               "feeDetail": [
        //                  {
        //                     "feeCoin": "USDT",
        //                     "deduction": "no",
        //                     "totalDeductionFee": "0",
        //                     "totalFee": "-0.0048522"
        //                  }
        //               ],
        //               "cTime": "1714471276596",
        //               "uTime": "1714471276596"
        //            }
        // spot private
        //        {
        //           "orderId": "1169142457356959747",
        //           "tradeId": "1169142457636958209",
        //           "symbol": "LTCUSDT",
        //           "orderType": "market",
        //           "side": "buy",
        //           "priceAvg": "81.069",
        //           "size": "0.074",
        //           "amount": "5.999106",
        //           "tradeScope": "taker",
        //           "feeDetail": [
        //              {
        //                 "feeCoin": "LTC",
        //                 "deduction": "no",
        //                 "totalDeductionFee": "0",
        //                 "totalFee": "0.000074"
        //              }
        //           ],
        //           "cTime": "1714471204194",
        //           "uTime": "1714471204194"
        //        }
        //
        // uta private
        //
        //     {
        //         "symbol": "BTCUSDT",
        //         "orderType": "market",
        //         "updatedTime": "1736378720623",
        //         "side": "buy",
        //         "orderId": "1288888888888888888",
        //         "execPnl": "0",
        //         "feeDetail": [
        //             {
        //                 "feeCoin": "USDT",
        //                 "fee": "0.569958"
        //             }
        //         ],
        //         "execTime": "1736378720623",
        //         "tradeScope": "taker",
        //         "tradeSide": "open",
        //         "execId": "1288888888888888888",
        //         "execLinkId": "1288888888888888888",
        //         "execPrice": "94993",
        //         "holdSide": "long",
        //         "execValue": "949.93",
        //         "category": "USDT-FUTURES",
        //         "execQty": "0.01",
        //         "clientOid": "1288888888888888889"
        // uta
        //
        //     {
        //         "i": "1344534089797185549", // Fill execution ID
        //         "L": "1344534089797185550", // Execution correlation ID
        //         "p": "110878.5", // Fill price
        //         "v": "0.07", // Fill size
        //         "S": "buy", // Fill side
        //         "T": "1756287827920" // Fill timestamp
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object instId = this.safeString2(trade, "symbol", "instId");
        Object posMode = this.safeString(trade, "posMode");
        Object category = this.safeString(trade, "category");
        Object defaultType = null;
        if (Helpers.isTrue(!Helpers.isEqual(category, null)))
        {
            defaultType = ((Helpers.isTrue((!Helpers.isEqual(category, "SPOT"))))) ? "contract" : "spot";
        } else
        {
            defaultType = ((Helpers.isTrue((!Helpers.isEqual(posMode, null))))) ? "contract" : "spot";
        }
        if (Helpers.isTrue(Helpers.isEqual(market, null)))
        {
            market = this.safeMarket(instId, null, null, defaultType);
        }
        Object timestamp = this.safeIntegerN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("uTime", "cTime", "ts", "T", "execTime")));
        Object feeDetail = this.safeList(trade, "feeDetail", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object first = this.safeDict(feeDetail, 0);
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(first, null)))
        {
            Object feeCurrencyId = this.safeString(first, "feeCoin");
            Object feeCurrencyCode = this.safeCurrencyCode(feeCurrencyId);
            final Object finalFirst = first;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", Precise.stringAbs(BitgetCore.this.safeString2(finalFirst, "totalFee", "fee")) );
                put( "currency", feeCurrencyCode );
            }};
        }
        final Object finalMarket = market;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "id", BitgetCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("tradeId", "i", "execId"))) );
            put( "order", BitgetCore.this.safeString2(trade, "orderId", "L") );
            put( "timestamp", timestamp );
            put( "datetime", BitgetCore.this.iso8601(timestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "type", BitgetCore.this.safeString(trade, "orderType") );
            put( "side", BitgetCore.this.safeString2(trade, "side", "S") );
            put( "takerOrMaker", BitgetCore.this.safeString(trade, "tradeScope") );
            put( "price", BitgetCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("priceAvg", "price", "execPrice", "P"))) );
            put( "amount", BitgetCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("size", "baseVolume", "execQty", "v"))) );
            put( "cost", BitgetCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("amount", "quoteVolume", "execValue"))) );
            put( "fee", finalFee );
        }}, market);
    }

